const book = $input.first().json;

const systemPrompt = 'Eres un experto en literatura. Creas resumenes detallados en espanol con tono amigable y motivador.';

const userPrompt = 'Crea un resumen completo del libro "' + book.title + '" de ' + book.author + ' (genero: ' + book.genre + '). Incluye:\n\n' +
  '1) Sinopsis en 2 parrafos.\n\n' +
  '2) 10 insights mas importantes priorizados del mas al menos importante. Cada insight debe tener un titulo en negrita y aproximadamente 200 palabras de desarrollo.\n\n' +
  '3) Expande en 500 palabras los argumentos en contra y a favor de estos insights de forma especifica: no argumentos genericos del libro sino tensiones reales, criticas academicas o practicas, contraejemplos documentados y defensas solidas. Cita autores, estudios o casos concretos cuando sea posible.\n\n' +
  '4) Para cada insight, dame dos ejercicios practicos y aplicables a la vida cotidiana. Cada ejercicio debe tener: Nombre, Objetivo en una linea, Instrucciones paso a paso (maximo 5 pasos), Frecuencia sugerida y una Metrica simple para saber si esta funcionando.\n\n' +
  '5) Por que leerlo.\n\n' +
  'Contexto sobre mi para personalizar los ejercicios: soy Alejandro, edad 43, casado con Gina por mas de 25 anos con dos hijos Mia y Alejandro Nicolas. Tengo mas de 15 anos de experiencia laboral en banca y consultoria focalizado en estrategia, finanzas y transformacion. Adicionalmente soy docente de MBA en la Universidad Iberoamericana en la Republica Dominicana. Me interesa aprender sobre como aplicar la IA para ser mas productivo, eficaz y eficiente en todo lo que haga.';

return [{
  json: {
    book,
    groqPayload: {
      model: 'llama-3.3-70b-versatile',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user',   content: userPrompt   }
      ],
      temperature: 0.75,
      max_tokens: 6000
    }
  }
}];

const book = $('Preparar Request').first().json.book;
const aiResult = $input.first().json;
if (!aiResult.choices || !aiResult.choices[0]) throw new Error('Groq error: ' + JSON.stringify(aiResult));

const summary = aiResult.choices[0].message.content.trim();
const today = new Date().toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const fecha = today.charAt(0).toUpperCase() + today.slice(1);
const NL = String.fromCharCode(10);

// Encabezado del primer mensaje
const header = '📚 ' + book.title + NL + '✍️ ' + book.author + NL + '🏷️ ' + book.genre + NL + '📅 ' + fecha + NL + '─────────────────────';

// Dividir el summary en parrafos y agrupar en chunks de max 3500 chars
const paragraphs = summary.split(NL + NL);
const CHUNK_SIZE = 3500;
const chunks = [];
let current = '';

for (const para of paragraphs) {
  const candidate = current.length === 0 ? para : current + NL + NL + para;
  if (candidate.length > CHUNK_SIZE && current.length > 0) {
    chunks.push(current.trim());
    current = para;
  } else {
    current = candidate;
  }
}
if (current.trim().length > 0) chunks.push(current.trim());

const total = chunks.length;

// Primera parte lleva el encabezado
const results = chunks.map((chunk, i) => {
  const partLabel = '[' + (i + 1) + '/' + total + '] ' + book.title;
  const body = i === 0 ? header + NL + NL + chunk : chunk;
  return { json: { ntfyTitle: partLabel, message: body, part: i + 1, total } };
});

return results;

const chunks = $input.all();
const TOPIC = 'amaceo-books-resumen';
const DELAY_MS = 3000;
const results = [];

for (let i = 0; i < chunks.length; i++) {
  const item = chunks[i].json;

  const response = await fetch('https://ntfy.sh/' + TOPIC, {
    method: 'POST',
    headers: {
      'Title':        item.ntfyTitle,
      'Priority':     'default',
      'Tags':         'books,green_book',
      'Content-Type': 'text/plain; charset=utf-8'
    },
    body: item.message
  });

  const status = response.status;
  results.push({ json: { part: item.part, total: item.total, status } });
  console.log('Enviado ' + item.part + '/' + item.total + ' — HTTP ' + status);

  // Esperar entre mensajes para evitar rate limiting
  if (i < chunks.length - 1) {
    await new Promise(resolve => setTimeout(resolve, DELAY_MS));
  }
}

return results;
